const items = $input.all();
const results = [];

for (const item of items) {
  const binaryData = item.binary;
  if (binaryData && binaryData.data) {
    const buffer = await this.helpers.getBinaryDataBuffer(item.index || 0, 'data');
    const base64String = buffer.toString('base64');
    const mimeType = binaryData.data.mimeType || 'image/jpeg';
    results.push({
      json: {
        ...item.json,
        imageBase64: base64String,
        imageMimeType: mimeType,
        replyToken: $('When LINE Event Received').item.json.events[0].replyToken,
        lineUserId: $('When LINE Event Received').item.json.events[0].source.userId
      }
    });
  }
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  let text = item.json.text || item.json.response || '';

  // Extract JSON from response
  const jsonMatch = text.match(/\{[\s\S]*?\}/); 
  let nutrition = {
    food_name: 'Unknown',
    meal_type: 'snack',
    calories: 0,
    protein: 0,
    fat: 0,
    carbs: 0,
    confidence: 'low'
  };

  if (jsonMatch) {
    try {
      nutrition = JSON.parse(jsonMatch[0]);
    } catch (e) {
      // Keep defaults if parsing fails
    }
  }

  results.push({
    json: {
      ...nutrition,
      timestamp: new Date().toISOString(),
      lineUserId: item.json.lineUserId || $('Encode Image to Base64').item.json.lineUserId,
      replyToken: item.json.replyToken || $('Encode Image to Base64').item.json.replyToken
    }
  });
}

return results;

const items = $input.all();
const today = new Date().toISOString().split('T')[0];
const lineUserId = $('Extract Nutrition Data').item.json.lineUserId;

let dailyTotal = 0;
let mealCount = 0;

for (const item of items) {
  const ts = item.json.Timestamp || '';
  const uid = item.json.LINE_UID || '';
  if (ts.startsWith(today) && uid === lineUserId) {
    dailyTotal += Number(item.json.Calories) || 0;
    mealCount++;
  }
}

const nutrition = $('Extract Nutrition Data').item.json;

return [{
  json: {
    daily_total: dailyTotal,
    meal_count: mealCount,
    food_name: nutrition.food_name,
    calories: nutrition.calories,
    protein: nutrition.protein,
    fat: nutrition.fat,
    carbs: nutrition.carbs,
    confidence: nutrition.confidence,
    replyToken: nutrition.replyToken,
    lineUserId: nutrition.lineUserId
  }
}];

