const items = $input.all();
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

// Filter last 7 days
const weeklyMeals = items.filter(item => {
  const ts = new Date(item.json.Timestamp || '');
  return ts >= weekAgo && ts <= now;
});

// Group by date
const dailyCalories = {};
let totalCalories = 0;
let totalProtein = 0;
let totalFat = 0;
let totalCarbs = 0;
let mealCount = weeklyMeals.length;

for (const meal of weeklyMeals) {
  const date = (meal.json.Timestamp || '').split('T')[0];
  const cal = Number(meal.json.Calories) || 0;
  dailyCalories[date] = (dailyCalories[date] || 0) + cal;
  totalCalories += cal;
  totalProtein += Number(meal.json.Protein) || 0;
  totalFat += Number(meal.json.Fat) || 0;
  totalCarbs += Number(meal.json.Carbs) || 0;
}

const days = Object.keys(dailyCalories);
const avgCalories = days.length > 0 ? Math.round(totalCalories / days.length) : 0;

let highestDay = '';
let highestCal = 0;
for (const [date, cal] of Object.entries(dailyCalories)) {
  if (cal > highestCal) {
    highestCal = cal;
    highestDay = date;
  }
}

return [{
  json: {
    total_calories: totalCalories,
    avg_calories: avgCalories,
    highest_day: highestDay,
    highest_day_calories: highestCal,
    total_protein: Math.round(totalProtein),
    total_fat: Math.round(totalFat),
    total_carbs: Math.round(totalCarbs),
    meal_count: mealCount,
    days_tracked: days.length,
    daily_breakdown: dailyCalories
  }
}];

